const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION NOTIFICATIONS - DÉPARTS (XDEPSE)');
console.log('═══════════════════════════════════════════════════');
console.log(`Lignes reçues: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const d = item.json;
  let dest, codeKey, typeKey;

  if (d.niveau_escalade === 'PDG') {
    dest = { code: d.code_pdg, nom: d.nom_pdg, prenom: d.prenom_pdg, email: d.email_pdg, telephone: d.tel_pdg, chat_id: d.chat_id_pdg, langue: d.langue_pdg, bot: d.bot_pdg };
    codeKey = d.code_pdg; typeKey = 'PDG';
  } else if (d.niveau_escalade === 'DGA') {
    dest = { code: d.code_dga, nom: d.nom_dga, prenom: d.prenom_dga, email: d.email_dga, telephone: d.tel_dga, chat_id: d.chat_id_dga, langue: d.langue_dga, bot: d.bot_dga };
    codeKey = d.code_dga; typeKey = 'DGA';
  } else if (d.niveau_escalade === 'BAALLAH') {
    dest = { code: d.code_baallah, nom: d.nom_baallah, prenom: d.prenom_baallah, email: d.email_baallah, telephone: d.tel_baallah, chat_id: d.chat_id_baallah, langue: d.langue_baallah, bot: d.bot_baallah };
    codeKey = d.code_baallah; typeKey = 'BAALLAH';
  } else if (d.niveau_escalade === 'SUPERIEUR') {
    dest = { code: d.code_superieur, nom: d.nom_superieur, prenom: d.prenom_superieur, email: d.email_superieur, telephone: d.tel_superieur, chat_id: d.chat_id_superieur, langue: d.langue_superieur, bot: d.bot_superieur };
    codeKey = d.code_superieur; typeKey = 'SUPERIEUR';
  } else if (d.niveau_escalade === 'SALARIE') {
    dest = { code: d.code_createur, nom: d.nom_createur, prenom: d.prenom_createur, email: d.email_createur, telephone: d.tel_createur, chat_id: d.chat_id_createur, langue: d.langue_createur, bot: d.bot_createur };
    codeKey = d.code_createur; typeKey = 'SALARIE';
  } else if (d.niveau_escalade === 'FARHAT') {
    dest = { code: d.code_farhat, nom: d.nom_farhat, prenom: d.prenom_farhat, email: d.email_farhat, telephone: d.tel_farhat, chat_id: d.chat_id_farhat, langue: d.langue_farhat, bot: d.bot_farhat };
    codeKey = d.code_farhat; typeKey = 'FARHAT';
  } else {
    return;
  }

  const cleKey = `${typeKey}_${codeKey}`;

  if (!notifications[cleKey]) {
    notifications[cleKey] = {
      destinataire_principal: dest,
      type_destinataire: typeKey,
      niveau_escalade: d.niveau_escalade,
      createur_info: {
        code: d.code_createur, nom: d.nom_createur, prenom: d.prenom_createur,
        email: d.email_createur, telephone: d.tel_createur,
        chat_id: d.chat_id_createur, langue: d.langue_createur, bot: d.bot_createur
      },
      superieur: {
        code: d.code_superieur, nom: d.nom_superieur, prenom: d.prenom_superieur,
        email: d.email_superieur, telephone: d.tel_superieur,
        chat_id: d.chat_id_superieur, langue: d.langue_superieur, bot: d.bot_superieur
      },
      pdg:     { code: d.code_pdg,     nom: d.nom_pdg,     prenom: d.prenom_pdg,     email: d.email_pdg,     telephone: d.tel_pdg,     chat_id: d.chat_id_pdg,     langue: d.langue_pdg,     bot: d.bot_pdg },
      dga:     { code: d.code_dga,     nom: d.nom_dga,     prenom: d.prenom_dga,     email: d.email_dga,     telephone: d.tel_dga,     chat_id: d.chat_id_dga,     langue: d.langue_dga,     bot: d.bot_dga },
      farhat:  { code: d.code_farhat,  nom: d.nom_farhat,  prenom: d.prenom_farhat,  email: d.email_farhat,  telephone: d.tel_farhat,  chat_id: d.chat_id_farhat,  langue: d.langue_farhat,  bot: d.bot_farhat },
      baallah: { code: d.code_baallah, nom: d.nom_baallah, prenom: d.prenom_baallah, email: d.email_baallah, telephone: d.tel_baallah, chat_id: d.chat_id_baallah, langue: d.langue_baallah, bot: d.bot_baallah },
      dossiers: []
    };
  }

  notifications[cleKey].dossiers.push({
    num_dossier:           d.num_dossier,
    date_dossier:          d.date_dossier,
    code_salarie:          d.code_salarie,
    nom_prenom:            d.nom_prenom,
    nom_salarie:           d.nom_salarie,
    prenom_salarie:        d.prenom_salarie,
    email_salarie:         d.email_salarie,
    tel_salarie:           d.tel_salarie,
    matricule:             d.matricule,
    fonction:              d.fonction,
    date_embauche:         d.date_embauche,
    date_sortie:           d.date_sortie,
    date_creation:         d.date_creation,
    date_controle:         d.date_controle,
    date_limite:           d.date_limite,
    jours_depuis_creation: d.jours_depuis_creation,
    jours_restants:        d.jours_restants,
    delai_int:             d.delai_int,
    seuil_dga:             d.seuil_dga,
    createur: {
      code: d.code_createur, nom: d.nom_createur, prenom: d.prenom_createur,
      email: d.email_createur, telephone: d.tel_createur
    }
  });
});

const resultats = Object.values(notifications).map(notif => {
  const total    = notif.dossiers.length;
  const joursMin = Math.min(...notif.dossiers.map(s => s.jours_restants));
  const joursMax = Math.max(...notif.dossiers.map(s => s.jours_restants));
  const delaiInt = notif.dossiers[0]?.delai_int || 30;
  const seuilDga = notif.dossiers[0]?.seuil_dga || Math.floor(delaiInt / 2);

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire:      notif.type_destinataire,
    niveau_escalade:        notif.niveau_escalade,
    createur_info:          notif.createur_info,
    superieur:              notif.superieur,
    pdg:                    notif.pdg,
    dga:                    notif.dga,
    farhat:                 notif.farhat,
    baallah:                notif.baallah,
    dossiers:               notif.dossiers,
    statistiques: {
      total_dossiers: total,
      jours_min:      joursMin,
      jours_max:      joursMax,
      delai_int:      delaiInt,
      seuil_dga:      seuilDga
    },
    meta: {
      date_traitement:       new Date().toISOString(),
      peut_envoyer_email:    !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id,
      langue_message:        notif.destinataire_principal.langue || 'FRA'
    }
  };
});

console.log(`\n✅ Groupes structurés: ${resultats.length}`);
['PDG','DGA','BAALLAH','SUPERIEUR','SALARIE','FARHAT'].forEach(t => {
  console.log(`  - ${t}: ${resultats.filter(r => r.type_destinataire === t).length}`);
});
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

const inputData = $input.all();

function formaterDate(d) {
  if (!d) return 'N/A';
  try { return new Date(d).toLocaleDateString('fr-FR', { year: 'numeric', month: '2-digit', day: '2-digit' }); }
  catch(e) { return 'N/A'; }
}

function emoji(j) {
  if (j <= 2) return '🔴';
  if (j === 3) return '🟠';
  if (j === 4) return '🟡';
  if (j <= 8) return '🔵';
  return '🟢';
}
function esc(text) {
  if (text === null || text === undefined) return 'N/A';
  return String(text)
    .replace(/\\/g, '\\\\')
    .replace(/\./g, '\\.')
    .replace(/!/g, '\\!')
    .replace(/\-/g, '\\-')
    .replace(/\+/g, '\\+')
    .replace(/=/g, '\\=')
    .replace(/\|/g, '\\|')
    .replace(/\{/g, '\\{')
    .replace(/\}/g, '\\}')
    .replace(/\[/g, '\\[')
    .replace(/\]/g, '\\]')
    .replace(/\(/g, '\\(')
    .replace(/\)/g, '\\)')
    .replace(/</g, '\\<')
    .replace(/>/g, '\\>')
    .replace(/#/g, '\\#')
    .replace(/~/g, '\\~')
    .replace(/`/g, '\\`');
}

const TEMPLATES = {
  sujet: {
    PDG:      '🔴 ALERTE URGENTE - Dossiers départ non clôturés',
    DGA:      '🟠 INFO DGA - Dossiers départ à mi-délai',
    BAALLAH:  '🟠 INFO - Dossiers départ à mi-délai',
    SUPERIEUR:'🟠 IMPORTANT - Dossiers départ en attente',
    SALARIE:  '🟡 Rappel - Votre dossier de départ est en attente',
    FARHAT:   '🔵 INFO PRÉVENTIVE - Dossiers départ à surveiller'
  },
  intro: {
    PDG:      "ALERTE URGENTE - Les dossiers de départ suivants n'ont pas encore été clôturés",
    DGA:      'Information - Les dossiers de départ suivants ont atteint la moitié de leur délai sans traitement',
    BAALLAH:  'Information - Les dossiers de départ suivants ont atteint la moitié de leur délai sans traitement',
    SUPERIEUR:'Les dossiers de départ suivants requièrent votre attention en priorité',
    SALARIE:  'Rappel concernant votre dossier de départ en attente de traitement',
    FARHAT:   'Information préventive - Les dossiers de départ suivants approchent de leur délai limite'
  }
};

function genererEmail(data) {
  const dest    = data.destinataire_principal;
  const stats   = data.statistiques;
  const type    = data.type_destinataire;
  const dossiers = data.dossiers;

  const subject = `${TEMPLATES.sujet[type]} - ${stats.total_dossiers} dossier(s)`;

  let body = `Bonjour ${dest.prenom || ''} ${dest.nom || ''},\n\n`;
  body += `${TEMPLATES.intro[type]}\n\n`;
  body += `═══════════════════════════════════════════════════════════════\n`;
  body += `📊 STATISTIQUES\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;
  body += `${emoji(stats.jours_min)} Niveau escalade : ${data.niveau_escalade}\n`;
  body += `Total dossiers : ${stats.total_dossiers}\n`;
  body += `Délai minimum restant : ${stats.jours_min} jour(s)\n`;
  body += `Délai total paramétré : ${stats.delai_int} jour(s)\n`;
  if (type === 'DGA' || type === 'BAALLAH') body += `Seuil mi-délai : ${stats.seuil_dga} jour(s)\n`;

  body += `\n═══════════════════════════════════════════════════════════════\n`;
  body += `📁 LISTE DES DOSSIERS DE DÉPART CONCERNÉS\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;

  dossiers.forEach((s, i) => {
    body += `${i + 1}. ${emoji(s.jours_restants)} Dossier N° ${s.num_dossier}\n`;
    body += `   👤 Créé par   : ${s.createur.prenom || ''} ${s.createur.nom || ''}\n`;
    body += `   ──────────────────────────────────────\n`;
    body += `   👤 Salarié    : ${s.nom_prenom} (${s.code_salarie})\n`;
    body += `   🏷️  Fonction   : ${s.fonction || 'N/A'}\n`;
    body += `   📋 Matricule  : ${s.matricule && s.matricule.trim() ? s.matricule : 'Non attribué'}\n`;
    body += `   📅 Embauche   : ${formaterDate(s.date_embauche)}\n`;
    body += `   🚪 Sortie     : ${formaterDate(s.date_sortie)}\n`;
    body += `   🕐 Création   : ${formaterDate(s.date_creation)}\n`;
    if (s.date_controle && !String(s.date_controle).includes('1753')) {
      body += `   🗓️  Contrôle   : ${formaterDate(s.date_controle)}\n`;
    }
    body += `   ⏰ Restant    : ${s.jours_restants} jour(s) (limite : ${formaterDate(s.date_limite)})\n`;
    if (s.jours_restants <= 2) body += `   🚨 URGENT - Traitement immédiat requis\n`;
    body += `\n`;
  });

  body += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    body += `🚨 URGENT - Traitement immédiat requis\n`;
  } else if (type === 'DGA' || type === 'BAALLAH') {
    body += `📌 Ces dossiers ont dépassé la moitié du délai autorisé. Merci de vous assurer que les actions correctives sont engagées.\n`;
  } else {
    body += `📌 Veuillez traiter ces dossiers dans les meilleurs délais.\n`;
  }
  body += `═══════════════════════════════════════════════════════════════\n\n`;
  body += `Cordialement,\n\nService SI/IA - Jbel Annour\n\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 Message automatique - ${formaterDate(new Date().toISOString())}\n`;
  body += `Merci de ne pas répondre à cet email\n`;

  return { subject, body };
}

function genererTelegram(data) {
  const dest    = data.destinataire_principal;
  const stats   = data.statistiques;
  const type    = data.type_destinataire;
  const dossiers = data.dossiers;

  // ── EN-TÊTE ──────────────────────────────────────────────
  let text = `${emoji(stats.jours_min)} *${TEMPLATES.sujet[type]}*\n`;
  text += `━━━━━━━━━━━━━━━━━━━━━\n\n`;

  // ── DESTINATAIRE ─────────────────────────────────────────
  text += `📨 *Destinataire :* ${dest.prenom || ''} ${dest.nom || ''}\n`;
  text += `🏷️ *Niveau :* ${data.niveau_escalade}\n\n`;

  // ── STATISTIQUES ─────────────────────────────────────────
  text += `📊 *STATISTIQUES*\n`;
  text += `┣ Total dossiers: *${stats.total_dossiers}*\n`;
  text += `┣ Délai min restant: *${stats.jours_min} jour(s)*\n`;
  text += `┣ Délai total: *${stats.delai_int} jour(s)*\n`;
  if (type === 'DGA' || type === 'BAALLAH') {
    text += `┗ Seuil mi-délai: *${stats.seuil_dga} jour(s)*\n`;
  } else {
    text += `┗ Date traitement: *${formaterDate(new Date().toISOString())}*\n`;
  }
  text += `\n`;

  // ── LISTE DES DOSSIERS ────────────────────────────────────
  text += `📁 *LISTE DES DOSSIERS DE DÉPART*\n`;
  text += `━━━━━━━━━━━━━━━━━━━━━\n\n`;

  dossiers.slice(0, 5).forEach((s, i) => {
    const nomCreateur = `${s.createur.prenom || ''} ${s.createur.nom || ''}`.trim() || 'N/A';

    text += `${i + 1}\. ${emoji(s.jours_restants)} *N° ${s.num_dossier}*\n`;
    text += `   👤 *Créateur :* ${nomCreateur}\n`;
    text += `   ─────────────────────\n`;
    text += `   👤 Salarié  : ${s.nom_prenom || 'N/A'} \(${s.code_salarie}\)\n`;
    text += `   🏷️ Fonction : ${s.fonction || 'N/A'}\n`;
    text += `   📋 Matricule: ${s.matricule && s.matricule.trim() ? s.matricule : 'Non attribué'}\n`;
    text += `   📅 Embauche : ${formaterDate(s.date_embauche)}\n`;
    text += `   🚪 Sortie   : ${formaterDate(s.date_sortie)}\n`;
    text += `   🕐 Créé le  : ${formaterDate(s.date_creation)}\n`;
    if (s.date_controle && !String(s.date_controle).includes('1753')) {
      text += `   🗓️ Contrôle : ${formaterDate(s.date_controle)}\n`;
    }
    text += `   ⏰ Restant  : *${s.jours_restants} jour(s)*\n`;
    text += `   📅 Limite   : ${formaterDate(s.date_limite)}\n`;
    if (s.jours_restants <= 2) text += `   🚨 *URGENT - Traitement immédiat requis*\n`;
    text += `\n`;
  });

  if (dossiers.length > 5) {
    text += `_\.\.\. et ${dossiers.length - 5} autre\(s\) dossier\(s\) non affiché\(s\)_\n\n`;
  }

  // ── CONCLUSION ────────────────────────────────────────────
  text += `━━━━━━━━━━━━━━━━━━━━━\n`;
  if (stats.jours_min <= 2) text += `🚨 *URGENT - Traitement immédiat requis*\n`;
  else if (type === 'DGA' || type === 'BAALLAH') text += `📌 Ces dossiers ont dépassé la moitié du délai autorisé\.\n`;
  else text += `📌 Veuillez traiter ces dossiers dans les meilleurs délais\.\n`;
  text += `\n🤖 _Message automatique \- ${formaterDate(new Date().toISOString())}_\n`;

  return { text, parse_mode: 'MarkdownV2' };
}

const results = [];

inputData.forEach(item => {
  const data        = item.json;
  const emailMsg    = genererEmail(data);
  const telegramMsg = genererTelegram(data);

  // Message principal
  results.push({
    json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }
  });

  // CC Telegram : PDG → copie supérieur
  if (data.type_destinataire === 'PDG' && data.superieur?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.superieur,
      cc_pour_profil: 'SUPERIEUR',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }

  // CC Telegram : PDG → copie créateur
  if (data.type_destinataire === 'PDG' && data.createur_info?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.createur_info,
      cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }

  // CC Telegram : SUPERIEUR → copie créateur
  if (data.type_destinataire === 'SUPERIEUR' && data.createur_info?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.createur_info,
      cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }
});

console.log(`\n✅ Messages générés: ${results.length}`);
console.log(`  - Principaux: ${results.filter(r => r.json.type_envoi === 'PRINCIPAL').length}`);
console.log(`  - CC Telegram: ${results.filter(r => r.json.type_envoi === 'CC').length}`);
['PDG','DGA','BAALLAH','SUPERIEUR','SALARIE','FARHAT'].forEach(t => {
  console.log(`  - ${t}: ${results.filter(r => r.json.type_destinataire === t).length}`);
});
console.log('═══════════════════════════════════════════════════\n');

return results;
